import{_ as a,o as e,c as t,ag as r}from"./chunks/framework.Dcoxob_B.js";const l=JSON.parse('{"title":"Chapter 1: 永恒的回响","description":"","frontmatter":{},"headers":[],"relativePath":"小说/时空恋曲/Chapter1.md","filePath":"小说/时空恋曲/Chapter1.md","lastUpdated":1777252016000}'),o={name:"小说/时空恋曲/Chapter1.md"};function _(s,p,n,c,d,h){return e(),t("div",null,[...p[0]||(p[0]=[r('<h1 id="chapter-1-永恒的回响" tabindex="-1">Chapter 1: 永恒的回响 <a class="header-anchor" href="#chapter-1-永恒的回响" aria-label="Permalink to &quot;Chapter 1: 永恒的回响&quot;">​</a></h1><p>都市的喧嚣总像一张巨大的、永不停歇的网，将一切琐碎的生命线编织其中。在林晚的世界里，这份喧嚣是她的背景音，是她与历史的距离。她是一名历史系的本科生，更是一名对那些被时间尘封的碎片有着近乎偏执热爱的文物修复师。</p><p>那天下午，阳光透过博物馆厚重的玻璃窗洒落进来，空气中弥漫着陈旧木料和古老纸张特有的微尘气味。林晚正专注地修复一件唐代的青铜器，指尖在微观的裂纹间小心翼翼地穿梭。她沉浸在历史的重量中，直到一个异常的信号打破了这份平静。</p><p>那件青铜器，原本静默的表面，突然泛起了一丝极不自然的、仿佛星辰崩塌般的幽蓝微光。林晚猛地抬起头，目光穿过陈列柜，望向了博物馆角落那台老旧的、用于环境监测的设备。设备屏幕上，原本稳定的时间流速指标，突然跳动出了一个肉眼无法捕捉的、极不稳定的波动图。</p><p>她知道，这是时间本身在颤抖。</p><p>出于一种难以抑制的、历史学家特有的好奇心，她沿着设备波动最剧烈的方向走去——那是博物馆后方的储藏室，一个不被日常打扰的、充满历史遗物的角落。</p><p>储藏室的空气，突然变得冰冷而又厚重，仿佛时间在此地凝固了。幽蓝的光芒不再来自青铜器，而是从一个被厚重丝绒布覆盖的、看起来极为古老的木箱上散发出来。那木箱的纹路，仿佛不是人类雕刻出的，而是一种流动的、复杂的符文。</p><p>林晚的手颤抖着伸向丝绒。当她的指尖触碰到那冰凉的布料时，一股强大的、如同洪流般的吸力瞬间包裹了她。她没有时间尖叫，甚至没有时间理解发生了什么。周围的世界在瞬间被拉伸、扭曲，那些固定的家具、那些陈列柜，都化为一道道拉丝的、色彩崩解的光影。</p><p>下一秒，剧烈的冲击感和耳边的爆鸣声消失了。</p><p>取而代之的，是泥土的芬芳、寒冷的夜风，以及一种截然不同的、带着磅礴气势的压迫感。</p><p>她跌落在了一片被古老石阶环绕的庭院中。空气中弥漫着焚香和草药的气味，头顶是高耸入云的飞檐和雕龙戏珠的屋顶。这，不是博物馆，而是另一个时间、另一个世界的开端。</p><p>茫然之际，一个身影如同夜色中的鬼魅般，从高大的廊柱阴影中走出。</p><p>他身着一套样式古雅却透着疏离感的长衫，眉眼间带着一种极度清冷、近乎不近人情的傲气。他的五官如雕刻般精致，却被一层难以穿透的淡漠所覆盖。他身姿挺拔，仿佛是这片历史的具象化身。</p><p>顾清辞。</p><p>他的目光像是在审视一件不属于此处的、微不足道的错物。那双眼睛，深邃而又平静，仿佛能一眼看透一切虚妄。他停下脚步，看着这个身着与此环境格格不入的、带着现代气息的女子，唇边掠过一丝极难辨认的，带着审视和疑惑的冷笑。</p><p>时间，在这里，彻底地错乱了。</p>',16)])])}const m=a(o,[["render",_]]);export{l as __pageData,m as default};
